CREATE PROC [dbo].[TR_ORDER_UPDATE]
( 
	@order_number     nvarchar(200), 
	@customer         nvarchar(50), 
	@order_date       date, 
	@ship_date        date, 
	@etd              date, 
	@f_cancelled      nvarchar(5), 
	@choduyet         int = 0, 
	@Finished         bit = 0, 
	@IsPay            bit = 0, 
	@destination_port nvarchar(50), 
	@ship_to          nvarchar(50), 
	@remark           nvarchar(max), 
	@payment_term     nvarchar(200), 
	@update_by        nvarchar(50),
	@carton_marking   nvarchar(200),
	@cont_qty        decimal(18, 3) = 0,
	@cust_po_number nvarchar(200),
	@range nvarchar(200)
)
AS
BEGIN
    UPDATE tr_order
	 SET  customer = @customer, 
		 order_date = @order_date, 
		 ship_date = @ship_date, 
		 etd = @etd, 
		 f_cancelled = @f_cancelled, 
		 choduyet = @choduyet, 
		 Finished = @Finished, 
		 IsPay = @IsPay, 
		 destination_port = @destination_port, 
		 ship_to = @ship_to, 
		 remark = @remark, 
		 payment_term = @payment_term, 
		 update_date = GETDATE(), 
		 update_by = @update_by,
		 carton_marking = @carton_marking,
		 cont_qty = @cont_qty,
		 cust_po_number = @cust_po_number,
		 [range] = @range
    WHERE  order_number = @order_number
END","parseAnalysis":{"readsTables":[],"writesTables":["dbo.tr_order"],"flags":[],"suggestedTier":"B"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
